func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
    if fromAddr == "" || toAddr == "" || userName == "" || subject == "" || feedbackContent == "" {
        return "", errors.New("all parameters are required")
    }

    // Encode subject with UTF-8
    encoder := mime.QEncoding
    encodedSubject := encoder.Encode("UTF-8", subject)

    // Create the email header
    var buf bytes.Buffer

    buf.WriteString("From: " + fromAddr + "\r\n")
    buf.WriteString("To: " + toAddr + "\r\n")
    buf.WriteString("Subject: " + encodedSubject + "\r\n")
    buf.WriteString("MIME-Version: 1.0\r\n")
    buf.WriteString("Content-Type: text/html; charset=utf-8\r\n")
    buf.WriteString("Content-Transfer-Encoding: quoted-printable\r\n")
    buf.WriteString("\r\n")

    // Create the HTML body
