	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedbackContent,
	)

	// Construct email message using net/mail to ensure proper encoding
	msg := &mail.Message{
		Header: make(map[string][]string),
		Body:   strings.NewReader(htmlBody),
	}
	msg.Header["From"] = []string{fromAddr}
	msg.Header["To"] = []string{toAddr}
	msg.Header["Subject"] = []string{fmt.Sprintf("Feedback: %s", subject)}
	msg.Header["MIME-Version"] = []string{"1.0"}
	msg.Header["Content-Type"] = []string{"text/html; charset=UTF-8"}

	// Write message to buffer by manually constructing headers and body
	var buf bytes.Buffer
	for key, values := range msg.Header {
		for _, value := range values {
			buf.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
		}
	}
	buf.WriteString("\r\n")
	if _, err := buf.ReadFrom(msg.Body); err != nil {
		return "", err
	}

	return buf.String(), nil
}

