`

type EmailData struct {
	UserName        string
	Subject         string
	FeedbackContent string
}

func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Create email headers
	headers := fmt.Sprintf("From: %s\r\n", fromAddr)
	headers += fmt.Sprintf("To: %s\r\n", toAddr)
	headers += fmt.Sprintf("Subject: %s\r\n", subject)
	headers += "Content-Type: text/html; charset=UTF-8\r\n"
	headers += "MIME-Version: 1.0\r\n\r\n"

	// Parse the email template
	tmpl, err := template.New("email").Parse(emailTemplate)
	if err != nil {
		return "", err
	}

	// Prepare template data
	data := EmailData{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Execute template to generate HTML body
	var bodyBuffer bytes.Buffer
	if err = tmpl.Execute(&bodyBuffer, data); err != nil {
		return "", err
	}

	// Combine headers and body to form complete email
	emailBody = headers + bodyBuffer.String()
	return
}

