    <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; margin: 20px; }
        h1 { color: #333; border-bottom: 2px solid #ddd; padding-bottom: 10px; }
        .info-section { margin: 20px 0; }
        .label { font-weight: bold; color: #666; }
        .content { margin-left: 10px; }
        .feedback-content { background-color: #f9f9f9; padding: 15px; border-radius: 5px; margin-top: 10px; }
    </style>
</head>
<body>
    <h1>User Feedback</h1>

    <div class="info-section">
        <span class="label">Username:</span>
        <span class="content">{{.UserName}}</span>
    </div>

    <div class="info-section">
        <span class="label">Subject:</span>
        <span class="content">{{.Subject}}</span>
    </div>

    <div class="info-section">
        <span class="label">Feedback Content:</span>
        <div class="feedback-content">{{.FeedbackContent}}</div>
    </div>

    <div style="margin-top: 30px; padding-top: 20px; border-top: 1px solid #ddd; color: #999; font-size: 14px;">
        This email was automatically generated from user feedback.
    </div>
</body>
</html>`

	// Create template instance
	tmpl, err := template.New("feedbackEmail").Parse(emailTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	// Data to populate the template
	data := struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Render the HTML body
	var bodyBuffer bytes.Buffer
	err = tmpl.Execute(&bodyBuffer, data)
	if err != nil {
