package main

import (
	"fmt"
	"html"
	"net/mail"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	parsedFrom, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	parsedTo, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Construct email subject with prefix
	emailSubject := fmt.Sprintf("Feedback: %s", subject)
	encodedSubject, err := encodeSubject(emailSubject)
	if err != nil {
		return "", fmt.Errorf("failed to encode subject: %w", err)
	}

	// Construct email headers
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\nContent-Transfer-Encoding: 8bit\r\n\r\n",
		parsedFrom.String(),
		parsedTo.String(),
		encodedSubject,
	)

	// Escape user inputs to prevent XSS
	escapedUserName := html.EscapeString(userName)
	escapedSubject := html.EscapeString(subject)
	escapedContent := html.EscapeString(feedbackContent)

	// Construct HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

// encodeSubject encodes email subject using quoted-printable encoding if it contains non-ASCII characters
func encodeSubject(subject string) (string, error) {
	// Check if subject contains any non-ASCII characters
	hasNonASCII := false
	for _, b := range []byte(subject) {
		if b > 0x7F {
			hasNonASCII = true
			break
		}
	}

	if !hasNonASCII {
		return subject, nil
	}

	// Encode subject using quoted-printable
	var buf bytes.Buffer
	w := quotedprintable.NewWriter(&buf)
	if _, err := w.Write([]byte(subject)); err != nil {
		return "", err
	}
	if err := w.Close(); err != nil {
		return "", err
	}
	encoded := buf.String()

	return fmt.Sprintf("=?UTF-8?Q?%s?=", encoded), nil
}

