// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format
	parsedFrom, err := mail.ParseAddress(fromAddr)
	if err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}

	parsedTo, err := mail.ParseAddress(toAddr)
	if err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Prevent email header injection by checking for newline characters in user inputs
	for field, value := range map[string]string{"userName": userName, "subject": subject, "feedbackContent": feedbackContent} {
		if containsNewline(value) {
			return "", fmt.Errorf("invalid %s: contains newline characters", field)
		}
	}

	// Create email message
	var msg bytes.Buffer

	// Write headers
	headers := make(mail.Header)
	headers["From"] = []string{parsedFrom.String()}
	headers["To"] = []string{parsedTo.String()}
	headers["Subject"] = []string{fmt.Sprintf("Feedback: %s", subject)} // Subject will be properly encoded by mail package
	headers["MIME-Version"] = []string{"1.0"}
	headers["Content-Type"] = []string{"text/html; charset=UTF-8"}

	// Write headers to buffer
	for key, values := range headers {
		for _, value := range values {
			if _, err := fmt.Fprintf(&msg, "%s: %s\r\n", key, value); err != nil {
				return "", err
			}
		}
	}

	// Add header-body separator
	if _, err := msg.Write([]byte("\r\n")); err != nil {
		return "", err
	}

	// Sanitize user inputs to prevent XSS in HTML body
	sanitizedUserName := html.EscapeString(userName)
	sanitizedSubject := html.EscapeString(subject)
	sanitizedContent := html.EscapeString(feedbackContent)

	// Construct HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
  <style>
    pre {
      font-family: Arial, sans-serif;
      background-color: #f9f9f9;
      padding: 10px;
      border: 1px solid #ddd;
      white-space: pre-wrap; /* Allow wrapping for long lines */
      word-wrap: break-word; /* Break long words */
    }
  </style>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre>%s</pre>
  </div>
</body>
</html>`,
		sanitizedUserName,
		sanitizedSubject,
		sanitizedContent,
	)

	// Write HTML body to buffer
	if _, err := msg.Write([]byte(htmlBody)); err != nil {
		return "", err
	}

	return msg.String(), nil
}

// containsNewline checks if a string contains any newline characters
func containsNewline(s string) bool {
	return bytes.ContainsAny([]byte(s), "\r\n")
}

