	"html/template"
)

func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Define the HTML email template
	tpl := `
<html>
<head>
    <title>User Feedback</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 20px; }
        .feedback-container { border: 1px solid #ddd; padding: 20px; border-radius: 5px; }
        .user-info { font-weight: bold; }
        .subject { font-size: 18px; margin-top: 10px; }
        .content { margin-top: 15px; }
    </style>
</head>
<body>
    <h1>New User Feedback</h1>
    <div class="feedback-container">
        <p class="user-info">From: {{.UserName}}</p>
        <p class="subject">Subject: {{.Subject}}</p>
        <div class="content">
            <strong>Feedback:</strong><br>
            {{.Content}}
        </div>
    </div>
</body>
</html>
`

	// Parse the email template
	tmpl, err := template.New("email").Parse(tpl)
	if err != nil {
		return "", err
	}

	// Create data structure for template execution
	data := struct {
		UserName string
		Subject  string
		Content  string
	}{
		UserName: userName,
		Subject:  subject,
		Content:  feedbackContent,
	}

	// Execute the template to generate HTML body
	var buf bytes.Buffer
	if err := tmpl.Execute(&buf, data); err != nil {
		return "", err
	}

	// Construct the complete email with headers
	headers := map[string]string{
		"From":         fromAddr,
		"To":           toAddr,
		"Subject":      subject,
		"MIME-Version": "1.0",
		"Content-Type": "text/html; charset=UTF-8",
	}

	// Build the email string
	var email bytes.Buffer
	for key, value := range headers {
		email.WriteString(key + ": " + value + "\r\n")
	}
	email.WriteString("\r\n") // Separate headers from body
	email.WriteString(buf.String())

	return email.String(), nil
}

