	// Define the HTML template for the email body
	tmpl := `
<html>
<head>
    <meta charset="UTF-8">
    <style>
        body {
            font-family: Arial, sans-serif;
            line-height: 1.6;
            color: #333;
            background-color: #f5f5f5;
            padding: 20px;
        }
        .container {
            max-width: 800px;
            margin: 0 auto;
            background-color: #ffffff;
            padding: 20px;
            border-radius: 8px;
            box-shadow: 0 0 10px rgba(0,0,0,0.1);
        }
        h2 {
            color: #444;
            border-bottom: 2px solid #eeeeee;
            padding-bottom: 10px;
        }
        .info-section {
            margin: 10px 0;
            padding: 10px;
            background-color: #f9f9f9;
            border-radius: 4px;
        }
        .info-section strong {
            color: #555;
        }
        .content {
            margin: 20px 0;
            padding: 15px;
            border: 1px solid #ddd;
            border-radius: 4px;
            background-color: #fafafa;
            white-space: pre-wrap;
        }
    </style>
</head>
<body>
    <div class="container">
        <h2>User Feedback</h2>
        <div class="info-section">
            <p><strong>Username:</strong> {{.UserName}}</p>
            <p><strong>Subject:</strong> {{.Subject}}</p>
        </div>
        <div>
            <p><strong>Feedback Content:</strong></p>
            <div class="content">{{.FeedbackContent}}</div>
        </div>
    </div>
</body>
</html>
`

	// Parse the template
	t, err := template.New("feedback").Parse(tmpl)
	if err != nil {
		return "", fmt.Errorf("failed to parse template: %w", err)
	}

	// Data to populate the template
	data := struct {
		UserName        string
		Subject         string
		FeedbackContent string
	}{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
	}

	// Execute the template to generate HTML body
	var htmlBody bytes.Buffer
	if err = t.Execute(&htmlBody, data); err != nil {
		return "", fmt.Errorf("failed to execute template: %w", err)
	}

	// Construct complete email with all necessary headers
	email := fmt.Sprintf(
		"From: %s\r\n"+
			"To: %s\r\n"+
			"Subject: %s\r\n"+
			"MIME-Version: 1.0\r\n"+
			"Content-Type: text/html; charset=UTF-8\r\n"+
			"\r\n"+
			"%s",
		fromAddr,
		toAddr,
		subject,
		htmlBody.String(),
	)

	return email, nil
}

func main() {
	// Example usage
	from := "user@example.com"
	to := "support@example.com"
	user := "John Doe"
	subj := "Issue with login"
	content := "I'm having trouble logging into my account. Whenever I try to sign in, I get an error message saying 'Invalid credentials' even though I'm sure I'm entering the correct password. Please help me resolve this issue."

	email, err := BuildFeedbackEmail(from, to, user, subj, content)
	if err != nil {
		fmt.Printf("Error building email: %v\n", err)
		return
	}

	fmt.Println("Generated Email:")
	fmt.Println("----------------")
	fmt.Println(email)
}

