            <span class="label">Subject:</span> {{.Subject}}
        </div>
        <div class="info-item">
            <span class="label">Content:</span>
            <div class="content">{{.FeedbackContent}}</div>
        </div>
    </div>
</body>
</html>
`

type emailData struct {
	UserName         string
	Subject          string
	FeedbackContent string
}

func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Parse the email template
	tmpl, err := template.New("feedback").Parse(emailTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse template: %w", err)
	}

	// Prepare data for template rendering
	data := emailData{
		UserName:         userName,
		Subject:          subject,
		FeedbackContent: feedbackContent,
	}

	// Render the template to get the HTML body
	var body bytes.Buffer
	if err := tmpl.Execute(&body, data); err != nil {
		return "", fmt.Errorf("failed to render template: %w", err)
	}

	// Build the email headers
	header := make(map[string]string)
	header["From"] = fromAddr
	header["To"] = toAddr
	header["Subject"] = subject
	header["MIME-Version"] = "1.0"
	header["Content-Type"] = `text/html; charset="UTF-8"`

	// Construct the full email by combining headers and body
	var buf bytes.Buffer
	for k, v := range header {
		buf.WriteString(fmt.Sprintf("%s: %s\r\n", k, v))
	}
	buf.WriteString("\r\n")
	buf.Write(body.Bytes())

	return buf.String(), nil
}

// Main function is for testing purposes
func main() {
	// Example usage
	from := "user@example.com"
	to := "support@example.com"
	userName := "John Doe"
	subject := "Issue with login functionality"
